@@ -1625,7 +1665,7 @@ pcnet32_open(struct net_device *dev)
 			dev->name);
 	}
     }
-    {
+    if (lp->phycount < 2) {
 	/*
 	 * 24 Jun 2004 according AMD, in order to change the PHY,
